      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_3),
      .readdata2(IN2_3),
      .readdata3(IN3_3),
      .readdata4(IN4_3),
      .writedata(network_datain_3)
  );

  DataRAM u_InterRAM (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_4),
      .readdata2(IN2_4),
      .readdata3(IN3_4),
      .readdata4(IN4_4),
      .readdata5(Last_FF_Value),
      .writedata(BP_out),
      .MISO(MISO),
      .SCK(SCK),
      .CS(CS2)
  );

  mux6_to_1 u0_mux6_to_1 (
      .IN0(IN1_0),
      .IN1(IN1_1),
      .IN2(IN1_2),
      .IN3(IN1_3),
      .IN4(IN1_4),
      .IN5(IN1_5),
      .Sel(rom_data[30:28]),
      .Dataout(LUT_Sel_1)
  );

  mux6_to_1 u1_mux6_to_1 (
      .IN0(IN2_0),
      .IN1(IN2_1),
      .IN2(IN2_2),
      .IN3(IN2_3),
      .IN4(IN2_4),
      .IN5(IN2_5),
      .Sel(rom_data[33:31]),
      .Dataout(LUT_Sel_2)
  );

  mux6_to_1 u2_mux6_to_1 (
      .IN0(IN3_0),
      .IN1(IN3_1),
      .IN2(IN3_2),
      .IN3(IN3_3),
      .IN4(IN3_4),
      .IN5(IN3_5),
      .Sel(rom_data[36:34]),
      .Dataout(LUT_Sel_3)
  );

  mux6_to_1 u3_mux6_to_1 (
      .IN0(IN4_0),
      .IN1(IN4_1),
      .IN2(IN4_2),
      .IN3(IN4_3),
      .IN4(IN4_4),
      .IN5(IN4_5),
      .Sel(rom_data[39:37]),
      .Dataout(LUT_Sel_4)
  );

  mux5_to_1 u0_mux5_to_1 (
      .IN0(IN5_0),
      .IN1(LUT_Sel_1),
      .IN2(rom_data[40]),
      .IN3(Last_BP_out),
      .IN4(FF_out),
      .Sel(rom_data[94:91]),
      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
