  ProgramCounter u_ProgramCounter (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .flag(flag),
      .pc(pc),
      .PC_Addr(pc_addr)
  );

  reg CS_0;
  reg flag_0;
  always @(posedge sys_rst) begin
    if (flag) begin
      CS_0   <= CS_2;
      flag_0 <= 1'b1;
    end else begin
      CS_0   <= CS_1;
      flag_0 <= 1'b0;
    end
  end


  TS1N28HPCPHVTB128X32M4SWBASO instr_mem_1(
      .SLP(1'b0),
      .SD(1'b0),
    .CLK(sys_clk),
      .CEB(CS_0),
      .WEB(flag_0),
      .CEBM(1'b1),
      .WEBM(1'b1),
      .AWT(1'b0),
    .A(pc_addr),
      .D(MOSI_out[31:0]),
      .BWEB(32'h0),
      .AM(7'h0),
      .DM(32'h0),
      .BWEBM(32'hFFFF_FFFF),
      .BIST(1'b0),
    .Q(rom_data[31:0])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_2(
    .SLP(1'b0),
    .SD(1'b0),
