  );

  mux6_to_1 u2_mux6_to_1 (
      .IN0(IN3_0),
      .IN1(IN3_1),
      .IN2(IN3_2),
      .IN3(IN3_3),
      .IN4(IN3_4),
      .IN5(IN3_5),
      .Sel(rom_data[36:34]),
      .Dataout(LUT_Sel_3)
  );

  mux6_to_1 u3_mux6_to_1 (
