    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[95:64]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[95:64])
);



  ExterDataRAM u_ExterRAM_0 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
