  always @(negedge SCK or negedge sys_rst) begin
    if (!sys_rst) begin
      MOSI_out <= MOSI_out_1;
      MOSI_out_1 <= 96'd0;
      m <= 7'd95;
    end else begin
      if (m != 7'd127) begin
        MOSI_out_1[m] <= MOSI;
        m <= m - 1;
      end
    end
  end

  //previous 2 clock pc_addr
  reg [Addr_Width-1:0] Last_1_pcaddr;
