      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_1),
      .readdata2(IN2_1),
      .readdata3(IN3_1),
      .readdata4(IN4_1),
      .writedata(network_datain_1)
  );

  ExterDataRAM u_ExterRAM_2 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
