    if (flag) begin
      CS_0   <= CS_2;
      flag_0 <= 1'b1;
    end else begin
      CS_0   <= CS_1;
      flag_0 <= 1'b0;
    end
  end


  TS1N28HPCPHVTB128X32M4SWBASO instr_mem_1(
      .SLP(1'b0),
      .SD(1'b0),
    .CLK(sys_clk),
      .CEB(CS_0),
      .WEB(flag_0),
      .CEBM(1'b1),
      .WEBM(1'b1),
      .AWT(1'b0),
    .A(pc_addr),
      .D(MOSI_out[31:0]),
      .BWEB(32'h0),
      .AM(7'h0),
      .DM(32'h0),
      .BWEBM(32'hFFFF_FFFF),
      .BIST(1'b0),
    .Q(rom_data[31:0])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_2(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[63:32]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[63:32])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_3(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[95:64]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[95:64])
);



  ExterDataRAM u_ExterRAM_0 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_0),
      .readdata2(IN2_0),
      .readdata3(IN3_0),
      .readdata4(IN4_0),
      .writedata(u_network_datain_0)
  );

  ExterDataRAM u_ExterRAM_1 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_1),
      .readdata2(IN2_1),
      .readdata3(IN3_1),
      .readdata4(IN4_1),
      .writedata(network_datain_1)
  );

  ExterDataRAM u_ExterRAM_2 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_2),
      .readdata2(IN2_2),
      .readdata3(IN3_2),
      .readdata4(IN4_2),
      .writedata(network_datain_2)
  );

  ExterDataRAM u_ExterRAM_3 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_3),
      .readdata2(IN2_3),
      .readdata3(IN3_3),
      .readdata4(IN4_3),
      .writedata(network_datain_3)
  );

  DataRAM u_InterRAM (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_4),
      .readdata2(IN2_4),
      .readdata3(IN3_4),
      .readdata4(IN4_4),
      .readdata5(Last_FF_Value),
      .writedata(BP_out),
      .MISO(MISO),
      .SCK(SCK),
      .CS(CS2)
  );

  mux6_to_1 u0_mux6_to_1 (
      .IN0(IN1_0),
      .IN1(IN1_1),
      .IN2(IN1_2),
      .IN3(IN1_3),
      .IN4(IN1_4),
      .IN5(IN1_5),
      .Sel(rom_data[30:28]),
      .Dataout(LUT_Sel_1)
  );

  mux6_to_1 u1_mux6_to_1 (
      .IN0(IN2_0),
      .IN1(IN2_1),
      .IN2(IN2_2),
      .IN3(IN2_3),
      .IN4(IN2_4),
      .IN5(IN2_5),
      .Sel(rom_data[33:31]),
      .Dataout(LUT_Sel_2)
  );

  mux6_to_1 u2_mux6_to_1 (
      .IN0(IN3_0),
      .IN1(IN3_1),
      .IN2(IN3_2),
      .IN3(IN3_3),
      .IN4(IN3_4),
