  //Logic_Element
  wire [                 15:0] LUT;
  wire                         LUT_Sel_1;
  wire                         LUT_Sel_2;
  wire                         LUT_Sel_3;
  wire                         LUT_Sel_4;

  //Last one BP output
  wire                         u_network_datain_0;
  assign u_network_datain_0 = rom_data[89] ? 1'b0 : network_datain_0;
