  wire                         IN5_0;

  //Logic_Element
  wire [                 15:0] LUT;
  wire                         LUT_Sel_1;
  wire                         LUT_Sel_2;
  wire                         LUT_Sel_3;
  wire                         LUT_Sel_4;

  //Last one BP output
  wire                         u_network_datain_0;
  assign u_network_datain_0 = rom_data[89] ? 1'b0 : network_datain_0;
  wire CS_1;
  assign CS_1 = !CS;
  wire CS_2;
  assign CS_2 = !CS2;


  wire out;
  reg  write = 1'b0;
  always @(sys_rst) begin
    if (sys_rst == 1'b0) write <= 1'b1;
    else write <= 1'b0;
  end

  always @(*) begin
    BP_out = out;
  end

  reg Last_BP_out;

  //FF Instruction Output
  wire FF_out;
  wire Last_FF_Value;
  reg [Instruction_Width-1:0] MOSI_out_1 = 96'b0;
  reg [Instruction_Width-1:0] MOSI_out = 96'b0;
  reg [6:0] m = 7'd95;

  always @(negedge SCK or negedge sys_rst) begin
    if (!sys_rst) begin
      MOSI_out <= MOSI_out_1;
      MOSI_out_1 <= 96'd0;
      m <= 7'd95;
    end else begin
      if (m != 7'd127) begin
        MOSI_out_1[m] <= MOSI;
        m <= m - 1;
      end
    end
  end

  //previous 2 clock pc_addr
  reg [Addr_Width-1:0] Last_1_pcaddr;
  reg [Addr_Width-1:0]Last_2_pcaddr;               //used to the alignment of writeaddr of DataRAM and ExterDataRAM

  //crossbar select
  assign network_sel_0 = rom_data[64:57];
  assign network_sel_1 = rom_data[72:65];
  assign network_sel_2 = rom_data[80:73];
  assign network_sel_3 = rom_data[88:81];

  //PC
  ProgramCounter u_ProgramCounter (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .flag(flag),
      .pc(pc),
      .PC_Addr(pc_addr)
  );

  reg CS_0;
  reg flag_0;
  always @(posedge sys_rst) begin
    if (flag) begin
      CS_0   <= CS_2;
      flag_0 <= 1'b1;
    end else begin
      CS_0   <= CS_1;
      flag_0 <= 1'b0;
    end
  end


  TS1N28HPCPHVTB128X32M4SWBASO instr_mem_1(
      .SLP(1'b0),
      .SD(1'b0),
    .CLK(sys_clk),
      .CEB(CS_0),
      .WEB(flag_0),
      .CEBM(1'b1),
      .WEBM(1'b1),
      .AWT(1'b0),
    .A(pc_addr),
      .D(MOSI_out[31:0]),
      .BWEB(32'h0),
      .AM(7'h0),
      .DM(32'h0),
      .BWEBM(32'hFFFF_FFFF),
      .BIST(1'b0),
    .Q(rom_data[31:0])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_2(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[63:32]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[63:32])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_3(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[95:64]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[95:64])
);



  ExterDataRAM u_ExterRAM_0 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_0),
      .readdata2(IN2_0),
      .readdata3(IN3_0),
      .readdata4(IN4_0),
      .writedata(u_network_datain_0)
  );

  ExterDataRAM u_ExterRAM_1 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_1),
      .readdata2(IN2_1),
      .readdata3(IN3_1),
      .readdata4(IN4_1),
      .writedata(network_datain_1)
  );

  ExterDataRAM u_ExterRAM_2 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_2),
      .readdata2(IN2_2),
      .readdata3(IN3_2),
      .readdata4(IN4_2),
