  wire [                 15:0] LUT;
  wire                         LUT_Sel_1;
  wire                         LUT_Sel_2;
  wire                         LUT_Sel_3;
  wire                         LUT_Sel_4;

  //Last one BP output
  wire                         u_network_datain_0;
  assign u_network_datain_0 = rom_data[89] ? 1'b0 : network_datain_0;
  wire CS_1;
  assign CS_1 = !CS;
  wire CS_2;
  assign CS_2 = !CS2;


  wire out;
  reg  write = 1'b0;
  always @(sys_rst) begin
    if (sys_rst == 1'b0) write <= 1'b1;
    else write <= 1'b0;
  end

