module BP_new_top_2_47 #(
    parameter Addr_Width = 'd7,                  //Depth of PC and Data Memory in Boolean Processor is 512, so Addr_Width is log2(512) ~ 'd9
    parameter Instruction_Width = 'd96,  //length of each instruction
    parameter BP_NUM = 'd256,  //the number of boolean processor in one cluster
    parameter Sel_Width = 'd8,  //select signal width of Inter_Cluster Crossbar
    parameter Depth = 'd128,
    parameter Sel_Width_transfer = 'd6           //select signal width of data transfer between clusters(Datawidth = 'd8, so Sel_Width_2 = 'd6)
) (
    input sys_clk,
    input sys_rst,
    input wire network_datain_0,
    network_datain_1,
    network_datain_2,
    network_datain_3,
    input MOSI,
    input CS,
    input CS2,
    input SCK,
    input flag,
    input [Addr_Width-1:0] pc,
    (*max_fanout="64"*) output reg BP_out,
    output wire [Sel_Width-1:0] network_sel_0,
    network_sel_1,
    network_sel_2,
    network_sel_3,
    output MISO
);

  wire [       Addr_Width-1:0] pc_addr;  //pc_addr��ProgramCounter����
  wire [Instruction_Width-1:0] rom_data;  //96bit instruction



  //Mux1 for select the 1th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN1_0;
  wire                         IN1_1;
  wire                         IN1_2;
  wire                         IN1_3;
  wire                         IN1_4;
  wire                         IN1_5;

  //Mux2 for select the 2th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN2_0;
  wire                         IN2_1;
  wire                         IN2_2;
  wire                         IN2_3;
  wire                         IN2_4;
  wire                         IN2_5;

  //Mux3 for select the 3th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN3_0;
  wire                         IN3_1;
  wire                         IN3_2;
  wire                         IN3_3;
  wire                         IN3_4;
  wire                         IN3_5;

  //Mux4 for select the 4th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN4_0;
  wire                         IN4_1;
  wire                         IN4_2;
  wire                         IN4_3;
  wire                         IN4_4;
  wire                         IN4_5;

  //Mux5 for select the output of Boolean Processor from four sources��four types of instruction��
  wire                         IN5_0;

  //Logic_Element
  wire [                 15:0] LUT;
  wire                         LUT_Sel_1;
  wire                         LUT_Sel_2;
  wire                         LUT_Sel_3;
  wire                         LUT_Sel_4;

  //Last one BP output
  wire                         u_network_datain_0;
  assign u_network_datain_0 = rom_data[89] ? 1'b0 : network_datain_0;
  wire CS_1;
  assign CS_1 = !CS;
  wire CS_2;
  assign CS_2 = !CS2;


  wire out;
  reg  write = 1'b0;
  always @(sys_rst) begin
    if (sys_rst == 1'b0) write <= 1'b1;
    else write <= 1'b0;
  end

  always @(*) begin
    BP_out = out;
  end

  reg Last_BP_out;

  //FF Instruction Output
  wire FF_out;
  wire Last_FF_Value;
  reg [Instruction_Width-1:0] MOSI_out_1 = 96'b0;
  reg [Instruction_Width-1:0] MOSI_out = 96'b0;
  reg [6:0] m = 7'd95;

  always @(negedge SCK or negedge sys_rst) begin
    if (!sys_rst) begin
      MOSI_out <= MOSI_out_1;
      MOSI_out_1 <= 96'd0;
      m <= 7'd95;
    end else begin
      if (m != 7'd127) begin
        MOSI_out_1[m] <= MOSI;
        m <= m - 1;
      end
    end
  end

  //previous 2 clock pc_addr
  reg [Addr_Width-1:0] Last_1_pcaddr;
  reg [Addr_Width-1:0]Last_2_pcaddr;               //used to the alignment of writeaddr of DataRAM and ExterDataRAM

  //crossbar select
  assign network_sel_0 = rom_data[64:57];
  assign network_sel_1 = rom_data[72:65];
  assign network_sel_2 = rom_data[80:73];
  assign network_sel_3 = rom_data[88:81];

  //PC
  ProgramCounter u_ProgramCounter (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .flag(flag),
      .pc(pc),
      .PC_Addr(pc_addr)
  );

  reg CS_0;
