      CS_0   <= CS_2;
      flag_0 <= 1'b1;
    end else begin
      CS_0   <= CS_1;
      flag_0 <= 1'b0;
    end
  end


  TS1N28HPCPHVTB128X32M4SWBASO instr_mem_1(
      .SLP(1'b0),
      .SD(1'b0),
    .CLK(sys_clk),
      .CEB(CS_0),
      .WEB(flag_0),
      .CEBM(1'b1),
      .WEBM(1'b1),
      .AWT(1'b0),
    .A(pc_addr),
      .D(MOSI_out[31:0]),
