  );

  mux6_to_1 u3_mux6_to_1 (
      .IN0(IN4_0),
      .IN1(IN4_1),
      .IN2(IN4_2),
      .IN3(IN4_3),
      .IN4(IN4_4),
      .IN5(IN4_5),
      .Sel(rom_data[39:37]),
      .Dataout(LUT_Sel_4)
  );

  mux5_to_1 u0_mux5_to_1 (
      .IN0(IN5_0),
      .IN1(LUT_Sel_1),
      .IN2(rom_data[40]),
      .IN3(Last_BP_out),
      .IN4(FF_out),
      .Sel(rom_data[94:91]),
      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
      .FF_opcode(rom_data[47:44]),
      .FF_Sel_1(LUT_Sel_1),
      .FF_Sel_2(LUT_Sel_2),
      .FF_Sel_3(LUT_Sel_3),
      .FF_Sel_4(LUT_Sel_4),
