module BP_new_top_3_15 #(
    parameter Addr_Width = 'd7,                  //Depth of PC and Data Memory in Boolean Processor is 512, so Addr_Width is log2(512) ~ 'd9
    parameter Instruction_Width = 'd96,  //length of each instruction
    parameter BP_NUM = 'd256,  //the number of boolean processor in one cluster
    parameter Sel_Width = 'd8,  //select signal width of Inter_Cluster Crossbar
    parameter Depth = 'd128,
    parameter Sel_Width_transfer = 'd6           //select signal width of data transfer between clusters(Datawidth = 'd8, so Sel_Width_2 = 'd6)
) (
    input sys_clk,
    input sys_rst,
    input wire network_datain_0,
    network_datain_1,
    network_datain_2,
    network_datain_3,
    input MOSI,
    input CS,
    input CS2,
    input SCK,
    input flag,
    input [Addr_Width-1:0] pc,
    (*max_fanout="64"*) output reg BP_out,
    output wire [Sel_Width-1:0] network_sel_0,
    network_sel_1,
    network_sel_2,
    network_sel_3,
    output MISO
);

  wire [       Addr_Width-1:0] pc_addr;  //pc_addr��ProgramCounter����
  wire [Instruction_Width-1:0] rom_data;  //96bit instruction



  //Mux1 for select the 1th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN1_0;
  wire                         IN1_1;
  wire                         IN1_2;
  wire                         IN1_3;
  wire                         IN1_4;
  wire                         IN1_5;

  //Mux2 for select the 2th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN2_0;
  wire                         IN2_1;
  wire                         IN2_2;
  wire                         IN2_3;
  wire                         IN2_4;
  wire                         IN2_5;

  //Mux3 for select the 3th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN3_0;
