      .Dataout(LUT_Sel_4)
  );

  mux5_to_1 u0_mux5_to_1 (
      .IN0(IN5_0),
      .IN1(LUT_Sel_1),
      .IN2(rom_data[40]),
      .IN3(Last_BP_out),
      .IN4(FF_out),
      .Sel(rom_data[94:91]),
      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
      .FF_opcode(rom_data[47:44]),
      .FF_Sel_1(LUT_Sel_1),
      .FF_Sel_2(LUT_Sel_2),
      .FF_Sel_3(LUT_Sel_3),
      .FF_Sel_4(LUT_Sel_4),
      .control(rom_data[43:40]),
      .Last_FF_Value(Last_FF_Value),
      .FF_out(FF_out)
  );

  //FF appropriative memory FFRAM
  FFRAM u_FFRAM (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .writedata(out),
      .opcode(rom_data[94:91]),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .readdata1(IN1_5),
      .readdata2(IN2_5),
      .readdata3(IN3_5),
      .readdata4(IN4_5)
  );

  //Reg previous BP_out
  always @(posedge sys_clk or posedge sys_rst) begin
    if (sys_rst) Last_BP_out <= 1'b0;
    else Last_BP_out <= BP_out;
  end

  //Reg previous 2 clock pc_addr
  always @(posedge sys_clk) begin
    Last_1_pcaddr <= pc_addr;
    Last_2_pcaddr <= Last_1_pcaddr;
  end

endmodule  //BP_new_top_3_18
module BP_new_top_3_19 #(
    parameter Addr_Width = 'd7,                  //Depth of PC and Data Memory in Boolean Processor is 512, so Addr_Width is log2(512) ~ 'd9
    parameter Instruction_Width = 'd96,  //length of each instruction
    parameter BP_NUM = 'd256,  //the number of boolean processor in one cluster
    parameter Sel_Width = 'd8,  //select signal width of Inter_Cluster Crossbar
    parameter Depth = 'd128,
    parameter Sel_Width_transfer = 'd6           //select signal width of data transfer between clusters(Datawidth = 'd8, so Sel_Width_2 = 'd6)
) (
    input sys_clk,
    input sys_rst,
    input wire network_datain_0,
    network_datain_1,
    network_datain_2,
    network_datain_3,
    input MOSI,
    input CS,
    input CS2,
    input SCK,
    input flag,
    input [Addr_Width-1:0] pc,
    (*max_fanout="64"*) output reg BP_out,
    output wire [Sel_Width-1:0] network_sel_0,
    network_sel_1,
    network_sel_2,
    network_sel_3,
    output MISO
);

  wire [       Addr_Width-1:0] pc_addr;  //pc_addr��ProgramCounter����
  wire [Instruction_Width-1:0] rom_data;  //96bit instruction



  //Mux1 for select the 1th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN1_0;
  wire                         IN1_1;
  wire                         IN1_2;
  wire                         IN1_3;
  wire                         IN1_4;
  wire                         IN1_5;

  //Mux2 for select the 2th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN2_0;
  wire                         IN2_1;
  wire                         IN2_2;
  wire                         IN2_3;
  wire                         IN2_4;
  wire                         IN2_5;

  //Mux3 for select the 3th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN3_0;
  wire                         IN3_1;
  wire                         IN3_2;
  wire                         IN3_3;
  wire                         IN3_4;
  wire                         IN3_5;

  //Mux4 for select the 4th input of LUT from InterRAM or ExterRAM or FF_RAM
  wire                         IN4_0;
  wire                         IN4_1;
  wire                         IN4_2;
  wire                         IN4_3;
  wire                         IN4_4;
  wire                         IN4_5;

  //Mux5 for select the output of Boolean Processor from four sources��four types of instruction��
  wire                         IN5_0;

  //Logic_Element
  wire [                 15:0] LUT;
  wire                         LUT_Sel_1;
  wire                         LUT_Sel_2;
  wire                         LUT_Sel_3;
  wire                         LUT_Sel_4;

  //Last one BP output
  wire                         u_network_datain_0;
  assign u_network_datain_0 = rom_data[89] ? 1'b0 : network_datain_0;
  wire CS_1;
  assign CS_1 = !CS;
  wire CS_2;
  assign CS_2 = !CS2;


  wire out;
  reg  write = 1'b0;
  always @(sys_rst) begin
    if (sys_rst == 1'b0) write <= 1'b1;
    else write <= 1'b0;
  end

  always @(*) begin
    BP_out = out;
  end

  reg Last_BP_out;

  //FF Instruction Output
  wire FF_out;
  wire Last_FF_Value;
  reg [Instruction_Width-1:0] MOSI_out_1 = 96'b0;
  reg [Instruction_Width-1:0] MOSI_out = 96'b0;
  reg [6:0] m = 7'd95;

  always @(negedge SCK or negedge sys_rst) begin
    if (!sys_rst) begin
      MOSI_out <= MOSI_out_1;
      MOSI_out_1 <= 96'd0;
      m <= 7'd95;
    end else begin
      if (m != 7'd127) begin
        MOSI_out_1[m] <= MOSI;
        m <= m - 1;
      end
    end
  end

  //previous 2 clock pc_addr
  reg [Addr_Width-1:0] Last_1_pcaddr;
  reg [Addr_Width-1:0]Last_2_pcaddr;               //used to the alignment of writeaddr of DataRAM and ExterDataRAM

  //crossbar select
  assign network_sel_0 = rom_data[64:57];
  assign network_sel_1 = rom_data[72:65];
  assign network_sel_2 = rom_data[80:73];
  assign network_sel_3 = rom_data[88:81];

  //PC
  ProgramCounter u_ProgramCounter (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .flag(flag),
      .pc(pc),
      .PC_Addr(pc_addr)
  );

  reg CS_0;
  reg flag_0;
  always @(posedge sys_rst) begin
    if (flag) begin
      CS_0   <= CS_2;
      flag_0 <= 1'b1;
    end else begin
      CS_0   <= CS_1;
      flag_0 <= 1'b0;
    end
  end


  TS1N28HPCPHVTB128X32M4SWBASO instr_mem_1(
      .SLP(1'b0),
      .SD(1'b0),
    .CLK(sys_clk),
      .CEB(CS_0),
      .WEB(flag_0),
      .CEBM(1'b1),
      .WEBM(1'b1),
      .AWT(1'b0),
    .A(pc_addr),
      .D(MOSI_out[31:0]),
      .BWEB(32'h0),
      .AM(7'h0),
      .DM(32'h0),
      .BWEBM(32'hFFFF_FFFF),
      .BIST(1'b0),
    .Q(rom_data[31:0])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_2(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[63:32]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[63:32])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_3(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[95:64]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[95:64])
);



  ExterDataRAM u_ExterRAM_0 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_0),
      .readdata2(IN2_0),
      .readdata3(IN3_0),
      .readdata4(IN4_0),
      .writedata(u_network_datain_0)
  );

  ExterDataRAM u_ExterRAM_1 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_1),
      .readdata2(IN2_1),
      .readdata3(IN3_1),
      .readdata4(IN4_1),
      .writedata(network_datain_1)
  );

  ExterDataRAM u_ExterRAM_2 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_2),
      .readdata2(IN2_2),
      .readdata3(IN3_2),
      .readdata4(IN4_2),
      .writedata(network_datain_2)
  );

  ExterDataRAM u_ExterRAM_3 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_3),
      .readdata2(IN2_3),
      .readdata3(IN3_3),
      .readdata4(IN4_3),
      .writedata(network_datain_3)
  );

  DataRAM u_InterRAM (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_4),
      .readdata2(IN2_4),
      .readdata3(IN3_4),
      .readdata4(IN4_4),
      .readdata5(Last_FF_Value),
      .writedata(BP_out),
      .MISO(MISO),
      .SCK(SCK),
      .CS(CS2)
  );

  mux6_to_1 u0_mux6_to_1 (
      .IN0(IN1_0),
      .IN1(IN1_1),
      .IN2(IN1_2),
      .IN3(IN1_3),
      .IN4(IN1_4),
      .IN5(IN1_5),
      .Sel(rom_data[30:28]),
      .Dataout(LUT_Sel_1)
  );

  mux6_to_1 u1_mux6_to_1 (
      .IN0(IN2_0),
      .IN1(IN2_1),
      .IN2(IN2_2),
      .IN3(IN2_3),
      .IN4(IN2_4),
      .IN5(IN2_5),
      .Sel(rom_data[33:31]),
      .Dataout(LUT_Sel_2)
  );

  mux6_to_1 u2_mux6_to_1 (
      .IN0(IN3_0),
      .IN1(IN3_1),
      .IN2(IN3_2),
      .IN3(IN3_3),
      .IN4(IN3_4),
      .IN5(IN3_5),
      .Sel(rom_data[36:34]),
      .Dataout(LUT_Sel_3)
  );

  mux6_to_1 u3_mux6_to_1 (
      .IN0(IN4_0),
      .IN1(IN4_1),
      .IN2(IN4_2),
      .IN3(IN4_3),
      .IN4(IN4_4),
      .IN5(IN4_5),
      .Sel(rom_data[39:37]),
      .Dataout(LUT_Sel_4)
  );

  mux5_to_1 u0_mux5_to_1 (
      .IN0(IN5_0),
      .IN1(LUT_Sel_1),
      .IN2(rom_data[40]),
      .IN3(Last_BP_out),
      .IN4(FF_out),
      .Sel(rom_data[94:91]),
      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
      .FF_opcode(rom_data[47:44]),
      .FF_Sel_1(LUT_Sel_1),
      .FF_Sel_2(LUT_Sel_2),
      .FF_Sel_3(LUT_Sel_3),
      .FF_Sel_4(LUT_Sel_4),
      .control(rom_data[43:40]),
      .Last_FF_Value(Last_FF_Value),
      .FF_out(FF_out)
  );

  //FF appropriative memory FFRAM
  FFRAM u_FFRAM (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .writedata(out),
      .opcode(rom_data[94:91]),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .readdata1(IN1_5),
      .readdata2(IN2_5),
      .readdata3(IN3_5),
      .readdata4(IN4_5)
  );

  //Reg previous BP_out
  always @(posedge sys_clk or posedge sys_rst) begin
    if (sys_rst) Last_BP_out <= 1'b0;
    else Last_BP_out <= BP_out;
  end

  //Reg previous 2 clock pc_addr
  always @(posedge sys_clk) begin
    Last_1_pcaddr <= pc_addr;
    Last_2_pcaddr <= Last_1_pcaddr;
  end

endmodule  //BP_new_top_3_19
