      .readdata5(Last_FF_Value),
      .writedata(BP_out),
      .MISO(MISO),
      .SCK(SCK),
      .CS(CS2)
  );

  mux6_to_1 u0_mux6_to_1 (
      .IN0(IN1_0),
      .IN1(IN1_1),
      .IN2(IN1_2),
      .IN3(IN1_3),
      .IN4(IN1_4),
