TS1N28HPCPHVTB128X32M4SWBASO instr_mem_3(
    .SLP(1'b0),
    .SD(1'b0),
    .CLK(sys_clk),
    .CEB(CS_0),
    .WEB(flag_0),
    .CEBM(1'b1),
    .WEBM(1'b1),
    .AWT(1'b0),
    .A(pc_addr),
    .D(MOSI_out[95:64]),
    .BWEB(32'h0),
    .AM(7'h0),
    .DM(32'h0),
    .BWEBM(32'hFFFF_FFFF),
    .BIST(1'b0),
    .Q(rom_data[95:64])
);



  ExterDataRAM u_ExterRAM_0 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_0),
      .readdata2(IN2_0),
      .readdata3(IN3_0),
      .readdata4(IN4_0),
      .writedata(u_network_datain_0)
  );

  ExterDataRAM u_ExterRAM_1 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_1),
      .readdata2(IN2_1),
      .readdata3(IN3_1),
      .readdata4(IN4_1),
      .writedata(network_datain_1)
  );

  ExterDataRAM u_ExterRAM_2 (
      .writeaddr(Last_2_pcaddr),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_2),
      .readdata2(IN2_2),
      .readdata3(IN3_2),
      .readdata4(IN4_2),
