  );

  mux6_to_1 u1_mux6_to_1 (
      .IN0(IN2_0),
      .IN1(IN2_1),
      .IN2(IN2_2),
      .IN3(IN2_3),
      .IN4(IN2_4),
      .IN5(IN2_5),
      .Sel(rom_data[33:31]),
      .Dataout(LUT_Sel_2)
  );

  mux6_to_1 u2_mux6_to_1 (
      .IN0(IN3_0),
      .IN1(IN3_1),
      .IN2(IN3_2),
      .IN3(IN3_3),
      .IN4(IN3_4),
