      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .clk(sys_clk),
      .readdata1(IN1_4),
      .readdata2(IN2_4),
      .readdata3(IN3_4),
      .readdata4(IN4_4),
      .readdata5(Last_FF_Value),
      .writedata(BP_out),
      .MISO(MISO),
      .SCK(SCK),
      .CS(CS2)
  );

  mux6_to_1 u0_mux6_to_1 (
      .IN0(IN1_0),
      .IN1(IN1_1),
      .IN2(IN1_2),
      .IN3(IN1_3),
      .IN4(IN1_4),
      .IN5(IN1_5),
      .Sel(rom_data[30:28]),
      .Dataout(LUT_Sel_1)
  );

  mux6_to_1 u1_mux6_to_1 (
      .IN0(IN2_0),
      .IN1(IN2_1),
      .IN2(IN2_2),
      .IN3(IN2_3),
      .IN4(IN2_4),
      .IN5(IN2_5),
      .Sel(rom_data[33:31]),
      .Dataout(LUT_Sel_2)
  );

  mux6_to_1 u2_mux6_to_1 (
      .IN0(IN3_0),
      .IN1(IN3_1),
      .IN2(IN3_2),
      .IN3(IN3_3),
      .IN4(IN3_4),
      .IN5(IN3_5),
      .Sel(rom_data[36:34]),
      .Dataout(LUT_Sel_3)
  );

  mux6_to_1 u3_mux6_to_1 (
      .IN0(IN4_0),
      .IN1(IN4_1),
      .IN2(IN4_2),
      .IN3(IN4_3),
      .IN4(IN4_4),
      .IN5(IN4_5),
      .Sel(rom_data[39:37]),
      .Dataout(LUT_Sel_4)
  );

  mux5_to_1 u0_mux5_to_1 (
      .IN0(IN5_0),
      .IN1(LUT_Sel_1),
      .IN2(rom_data[40]),
      .IN3(Last_BP_out),
      .IN4(FF_out),
      .Sel(rom_data[94:91]),
      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
      .FF_opcode(rom_data[47:44]),
      .FF_Sel_1(LUT_Sel_1),
      .FF_Sel_2(LUT_Sel_2),
      .FF_Sel_3(LUT_Sel_3),
      .FF_Sel_4(LUT_Sel_4),
      .control(rom_data[43:40]),
      .Last_FF_Value(Last_FF_Value),
      .FF_out(FF_out)
  );

  //FF appropriative memory FFRAM
  FFRAM u_FFRAM (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .writedata(out),
      .opcode(rom_data[94:91]),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
      .readaddr3(rom_data[20:14]),
      .readaddr4(rom_data[27:21]),
      .readdata1(IN1_5),
      .readdata2(IN2_5),
      .readdata3(IN3_5),
      .readdata4(IN4_5)
  );

  //Reg previous BP_out
  always @(posedge sys_clk or posedge sys_rst) begin
    if (sys_rst) Last_BP_out <= 1'b0;
    else Last_BP_out <= BP_out;
  end

  //Reg previous 2 clock pc_addr
  always @(posedge sys_clk) begin
    Last_1_pcaddr <= pc_addr;
    Last_2_pcaddr <= Last_1_pcaddr;
  end

endmodule  //BP_new_top_3_61
module BP_new_top_3_62 #(
    parameter Addr_Width = 'd7,                  //Depth of PC and Data Memory in Boolean Processor is 512, so Addr_Width is log2(512) ~ 'd9
    parameter Instruction_Width = 'd96,  //length of each instruction
    parameter BP_NUM = 'd256,  //the number of boolean processor in one cluster
