      .readaddr4(rom_data[27:21]),
      .readdata1(IN1_5),
      .readdata2(IN2_5),
      .readdata3(IN3_5),
      .readdata4(IN4_5)
  );

  //Reg previous BP_out
  always @(posedge sys_clk or posedge sys_rst) begin
