      .AM(7'h0),
      .DM(32'h0),
      .BWEBM(32'hFFFF_FFFF),
      .BIST(1'b0),
    .Q(rom_data[31:0])
);
TS1N28HPCPHVTB128X32M4SWBASO instr_mem_2(
