  //Logic_Element
  wire [                 15:0] LUT;
  wire                         LUT_Sel_1;
  wire                         LUT_Sel_2;
  wire                         LUT_Sel_3;
  wire                         LUT_Sel_4;

  //Last one BP output
  wire                         u_network_datain_0;
  assign u_network_datain_0 = rom_data[89] ? 1'b0 : network_datain_0;
  wire CS_1;
  assign CS_1 = !CS;
  wire CS_2;
  assign CS_2 = !CS2;


  wire out;
  reg  write = 1'b0;
  always @(sys_rst) begin
    if (sys_rst == 1'b0) write <= 1'b1;
    else write <= 1'b0;
  end

  always @(*) begin
    BP_out = out;
  end

  reg Last_BP_out;

  //FF Instruction Output
  wire FF_out;
  wire Last_FF_Value;
  reg [Instruction_Width-1:0] MOSI_out_1 = 96'b0;
  reg [Instruction_Width-1:0] MOSI_out = 96'b0;
  reg [6:0] m = 7'd95;

  always @(negedge SCK or negedge sys_rst) begin
    if (!sys_rst) begin
      MOSI_out <= MOSI_out_1;
      MOSI_out_1 <= 96'd0;
      m <= 7'd95;
    end else begin
      if (m != 7'd127) begin
        MOSI_out_1[m] <= MOSI;
        m <= m - 1;
      end
    end
  end

  //previous 2 clock pc_addr
