    network_datain_2,
    network_datain_3,
    input MOSI,
    input CS,
    input CS2,
    input SCK,
    input flag,
    input [Addr_Width-1:0] pc,
    (*max_fanout="64"*) output reg BP_out,
    output wire [Sel_Width-1:0] network_sel_0,
    network_sel_1,
    network_sel_2,
    network_sel_3,
