      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
