      .Sel(rom_data[39:37]),
      .Dataout(LUT_Sel_4)
  );

  mux5_to_1 u0_mux5_to_1 (
      .IN0(IN5_0),
      .IN1(LUT_Sel_1),
      .IN2(rom_data[40]),
      .IN3(Last_BP_out),
      .IN4(FF_out),
