      .IN3(Last_BP_out),
      .IN4(FF_out),
      .Sel(rom_data[94:91]),
      .Dataout(out)
  );

  //LogicElement����һ��LUT
  Logic_Element u_Logic_Element (
      .LUT(rom_data[55:40]),
      .sel1(LUT_Sel_1),
      .sel2(LUT_Sel_2),
      .sel3(LUT_Sel_3),
      .sel4(LUT_Sel_4),
      .LUT_out(IN5_0)
  );

  //FF support for yosys netlist(FF Instructions)
  FF_process u_FF_process (
      .FF_opcode(rom_data[47:44]),
      .FF_Sel_1(LUT_Sel_1),
      .FF_Sel_2(LUT_Sel_2),
      .FF_Sel_3(LUT_Sel_3),
      .FF_Sel_4(LUT_Sel_4),
      .control(rom_data[43:40]),
      .Last_FF_Value(Last_FF_Value),
      .FF_out(FF_out)
  );

  //FF appropriative memory FFRAM
  FFRAM u_FFRAM (
      .clk(sys_clk),
      .rst(sys_rst),
      .jump_flag(rom_data[90]),
      .writedata(out),
      .opcode(rom_data[94:91]),
      .readaddr1(rom_data[6:0]),
      .readaddr2(rom_data[13:7]),
